#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, K;
        scanf("%d %d", &N, &K);
        for (int i = 0; i < N; i++) {
            if (N % 2 == 1 || i % 2 == 1) {
                printf("%d ", K);
            } else {
                printf("1 ");
            }
        }
        printf("\n");
    }
    return 0;
}

