const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => lines[idx++];
const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const [N, K] = readline().split(' ').map(Number);
    let result = '';
    for (let j = 0; j < N; j++) {
        if (N % 2 == 1 || j % 2 == 1) {
            result += K + ' ';
        } else {
            result += 1 + ' ';
        }
    }
    console.log(result);
}
